class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int n = s.size(), m = p.size();
        int i = 0, j = 0;
        int start = 0, minLen = INT_MAX;
        vector<int> pIndex(m + 1, -1);
        pIndex[0] = 0;
        for (int k = 1; k <= m; ++k) {
            if (p[k - 1] == '*') {
                pIndex[k] = pIndex[k - 2];
            } else {
                pIndex[k] = pIndex[k - 1];
            }
        }
        while (i < n) {
            if (j < m && p[j] == s[i]) {
                i++;
                j++;
            } else if (j < m && p[j] == '*') {
                j = pIndex[j + 1];
                if (j == -1) {
                    i++;
                }
            } else {
                if (j == m) {
                    minLen = min(minLen, i - start);
                }
                start = i;
                j = pIndex[j];
                if (j == -1) {
                    i++;
                }
            }
        }
        if (j == m) {
            minLen = min(minLen, n - start);
        }
        return minLen == INT_MAX ? -1 : minLen;
    }
};
